function solve(nums) {
    function isPrime(n) {
        if (n <= 1) return false;
        if (n === 2) return true;
        if (n % 2 === 0) return false;
        for (let i = 3; i <= Math.sqrt(n); i += 2) {
            if (n % i === 0) return false;
        }
        return true;
    }

    let sumA = 0;
    let sumB = 0;

    for (let i = 0; i < nums.length; i++) {
        if (isPrime(i)) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }

    return Math.abs(sumA - sumB);
}
